def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    from pptx.enum.shapes import MSO_SHAPE_TYPE

    # Check slide 3 for calculator icon (picture/graphic shapes)
    ppt = Presentation(modified_ppt_path)
    if len(ppt.slides) <= 2:
        return ("Slide 3 does not exist.", 0.0)

    slide = ppt.slides[2]  # Slide 3 (0-indexed)

    # Look for picture/graphic shapes that could be calculator icons
    calculator_candidates = []
    for shape in slide.shapes:
        # Check for picture shapes
        if shape.shape_type == MSO_SHAPE_TYPE.PICTURE:
            calculator_candidates.append(shape)
        # Also check names/alt text for calculator references
        elif (hasattr(shape, 'name') and 'calc' in shape.name.lower()) or \
             (hasattr(shape, 'alternative_text') and shape.alternative_text and 'calc' in shape.alternative_text.lower()):
            calculator_candidates.append(shape)

    if calculator_candidates:
        return f"Calculator icon found on slide 3 ({len(calculator_candidates)} picture/graphic shape(s) detected).", 1.0

    # Fallback: use VLM to check the slide screenshot
    slide_screenshot = None
    for s in modified_ppt_screenshots:
        if s.slide_number == 3:
            slide_screenshot = s.image_path
            break

    if slide_screenshot:
        prompt = "Is there a calculator icon visible on this slide? Answer yes or no."
        try:
            response = vlm_call(prompt, [slide_screenshot], temperature=0.2, max_tokens=20)
            if "yes" in response.lower():
                return "Calculator icon detected by visual analysis on slide 3.", 1.0
        except:
            pass

    return "No calculator icon detected on slide 3.", 0.0

