def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    # Only the calculator icon should be added, no other significant extras
    ppt = Presentation(modified_ppt_path)
    ppt_orig = Presentation(original_ppt_path)

    # 1. Check number of shapes added to slide 3 (should be just one for calculator)
    if len(ppt.slides) <= 2 or len(ppt_orig.slides) <= 2:
        return ("Slide 3 missing in one of the presentations.", 0.0)

    slide3 = ppt.slides[2]
    orig_slide3 = ppt_orig.slides[2]
    added_shapes = len(slide3.shapes) - len(orig_slide3.shapes)

    if added_shapes > 1:
        return f"Too many shapes added to slide 3 (expected 1 calculator icon, got {added_shapes} additions).", 0.0
    elif added_shapes == 0:
        return "No shapes were added to slide 3 (calculator icon missing).", 0.0

    # 2. Check for changes to other slides (should be minimal)
    slides_with_changes = 0
    for i in range(len(ppt.slides)):
        if i == 2:  # Skip slide 3 as we expect changes there
            continue
        if i < len(ppt_orig.slides):
            if len(ppt.slides[i].shapes) != len(ppt_orig.slides[i].shapes):
                slides_with_changes += 1

    if slides_with_changes > 0:
        return f"Unexpected changes detected on {slides_with_changes} other slide(s).", 0.2

    # 3. Visual check for extraneous content on slide 3
    slide_screenshot = None
    for s in modified_ppt_screenshots:
        if s.slide_number == 3:
            slide_screenshot = s.image_path
            break

    if slide_screenshot:
        prompt = "Looking at this slide, is there only one new calculator icon added, or are there other new unrelated icons, images, or content? Answer 'calculator only' if just a calculator was added, or 'other content' if there are additional unrelated items."
        try:
            response = vlm_call(prompt, [slide_screenshot], temperature=0.2, max_tokens=15)
            if "calculator only" in response.lower() or ("calculator" in response.lower() and "only" in response.lower()):
                return "Visual check confirms only calculator icon was added.", 1.0
            elif "other content" in response.lower():
                return f"Visual check detects additional content beyond calculator icon.", 0.3
        except:
            pass

    # Default: if basic shape count check passed, give benefit of doubt
    return "No major extraneous content detected (one shape added to slide 3 as expected).", 1
